mapper.select:
SELECT EXISTS (
  SELECT 1
  FROM collab.collaboration_command_events candidate
  WHERE candidate.trip_id = #{tripId}
    AND candidate.actor_user_id = #{actorUserId}
    AND candidate.websocket_session_id = #{websocketSessionId}
    AND candidate.source IN ('USER', 'AI_TOOL', 'REDO')
    AND candidate.inverse_payload IS NOT NULL
    AND candidate.id IN (
      SELECT recent.id
      FROM collab.collaboration_command_events recent
      WHERE recent.trip_id = #{tripId}
        AND recent.actor_user_id = #{actorUserId}
        AND recent.websocket_session_id = #{websocketSessionId}
        AND recent.source IN ('USER', 'AI_TOOL', 'REDO')
        AND recent.inverse_payload IS NOT NULL
      ORDER BY recent.created_at DESC, recent.id DESC
      LIMIT 5
    )
    AND NOT EXISTS (
      SELECT 1
      FROM collab.collaboration_command_events undo_event
      WHERE undo_event.trip_id = candidate.trip_id
        AND undo_event.actor_user_id = candidate.actor_user_id
        AND undo_event.websocket_session_id = #{websocketSessionId}
        AND undo_event.source = 'UNDO'
        AND undo_event.payload ->> 'targetEventId' = candidate.id::text
        AND (
          undo_event.created_at > candidate.created_at
          OR (undo_event.created_at = candidate.created_at AND undo_event.id > candidate.id)
        )
    )
)
